package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Method;
import java.util.Map;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;

class CSVParserTest {

    private CSVParser parser;
    private Lexer lexerMock;
    private Token tokenMock;
    private Map<String, Integer> headerMapMock;

    @BeforeEach
    void setUp() throws Exception {
        // Mocks
        lexerMock = mock(Lexer.class);
        tokenMock = new Token();
        headerMapMock = mock(Map.class);

        // Create a CSVParser instance with a dummy Reader and CSVFormat
        Reader dummyReader = mock(Reader.class);
        CSVFormat dummyFormat = mock(CSVFormat.class);

        // Use constructor with reflection to inject mocks
        parser = new CSVParser(dummyReader, dummyFormat, 0L, 0L);
        // Inject mocks into private fields
        setField(parser, "lexer", lexerMock);
        setField(parser, "headerMap", headerMapMock);
        setField(parser, "recordList", new java.util.ArrayList<String>());
        setField(parser, "recordNumber", 0L);
        setField(parser, "characterOffset", 0L);
        setField(parser, "reusableToken", tokenMock);
    }

    @Test
    void testNextRecord_tokenToEOF() throws Exception {
        // Setup token sequence: TOKEN, TOKEN, EORECORD
        doAnswer(invocation -> {
            tokenMock.type = Token.Type.TOKEN;
            tokenMock.content = "value1";
            tokenMock.isReady = true;
            return null;
        }).doAnswer(invocation -> {
            tokenMock.type = Token.Type.TOKEN;
            tokenMock.content = "value2";
            tokenMock.isReady = true;
            return null;
        }).doAnswer(invocation -> {
            tokenMock.type = Token.Type.EORECORD;
            tokenMock.content = "value3";
            tokenMock.isReady = true;
            return null;
        }).when(lexerMock).nextToken(tokenMock);

        // Spy on addRecordValue to call real method
        CSVParser spyParser = spy(parser);
        doCallRealMethod().when(spyParser).addRecordValue(anyBoolean());

        // Call nextRecord()
        CSVRecord record = spyParser.nextRecord();

        // Verify record is not null and contains expected values
        assertNotNull(record);
        String[] values = record.values();
        assertEquals(3, values.length);
        assertArrayEquals(new String[]{"value1", "value2", "value3"}, values);

        // Verify recordNumber incremented
        assertEquals(1L, spyParser.getRecordNumber());

        // Verify headerMap passed to CSVRecord constructor
        assertSame(headerMapMock, getField(record, "headerMap"));
    }

    @Test
    void testNextRecord_commentToken() throws Exception {
        // Setup token sequence: COMMENT, TOKEN, EORECORD
        doAnswer(invocation -> {
            tokenMock.type = Token.Type.COMMENT;
            tokenMock.content = "comment line";
            tokenMock.isReady = true;
            return null;
        }).doAnswer(invocation -> {
            tokenMock.type = Token.Type.TOKEN;
            tokenMock.content = "value1";
            tokenMock.isReady = true;
            return null;
        }).doAnswer(invocation -> {
            tokenMock.type = Token.Type.EORECORD;
            tokenMock.content = "value2";
            tokenMock.isReady = true;
            return null;
        }).when(lexerMock).nextToken(tokenMock);

        CSVParser spyParser = spy(parser);
        doCallRealMethod().when(spyParser).addRecordValue(anyBoolean());

        CSVRecord record = spyParser.nextRecord();

        assertNotNull(record);
        assertEquals(2, record.size());
        assertEquals("comment line", record.getComment());
    }

    @Test
    void testNextRecord_invalidToken_throwsIOException() throws Exception {
        doAnswer(invocation -> {
            tokenMock.type = Token.Type.INVALID;
            tokenMock.isReady = true;
            return null;
        }).when(lexerMock).nextToken(tokenMock);

        IOException thrown = assertThrows(IOException.class, () -> parser.nextRecord());
        assertTrue(thrown.getMessage().contains("invalid parse sequence"));
    }

    @Test
    void testNextRecord_unexpectedToken_throwsIllegalStateException() throws Exception {
        doAnswer(invocation -> {
            tokenMock.type = Token.Type.EOF;
            tokenMock.isReady = false; // not ready, so no addRecordValue
            return null;
        }).when(lexerMock).nextToken(tokenMock);

        // Change token type after loop to something unexpected to trigger default
        // We do this by making reusableToken.type = a type not handled (simulate)

        // First call sets EOF with isReady false, loop ends
        // Then forcibly set token type to an unexpected enum value to trigger exception
        CSVParser spyParser = spy(parser);
        doCallRealMethod().when(spyParser).addRecordValue(anyBoolean());

        // Inject an unexpected token type after loop (simulate)
        doAnswer(invocation -> {
            tokenMock.type = Token.Type.EOF;
            tokenMock.isReady = false;
            return null;
        }).when(lexerMock).nextToken(tokenMock);

        // Use reflection to forcibly set token type to null or invalid type after nextToken
        // But enum cannot be null, so we simulate by subclassing or using reflection to set type to null

        // Instead, we can create a subclass of Token with an invalid type
        Token invalidToken = new Token() {
            @Override
            public String toString() {
                return "Invalid Token";
            }
        };
        setField(invalidToken, "type", null);
        setField(parser, "reusableToken", invalidToken);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> parser.nextRecord());
        assertTrue(thrown.getMessage().contains("Unexpected Token type"));
    }

    // Helper reflection methods
    private static void setField(Object target, String fieldName, Object value) throws Exception {
        java.lang.reflect.Field field = target.getClass().getDeclaredField(fieldName);
        field.setAccessible(true);
        field.set(target, value);
    }

    private static Object getField(Object target, String fieldName) throws Exception {
        java.lang.reflect.Field field = target.getClass().getDeclaredField(fieldName);
        field.setAccessible(true);
        return field.get(target);
    }
}
